 16→ * SQLite-backed StorageAdapter implementation using better-sqlite3.
 17→ * Constitution Principle III: Every query enforces tenant_id scoping.
 18→ * Constitution Principle V: Pluggable Architecture.
 19→ */
 20→
 21→import crypto from "node:crypto";
 22→import Database from "better-sqlite3";
 23→import type { StorageAdapter } from "./adapter.js";
 24→import type { QueryFilter, StorageMetadata, TransactionContext } from "./types.js";
 25→
 26→export interface SQLiteAdapterOptions {
 27→  dbPath: string;
 28→}
 29→
 30→export class SQLiteAdapter implements StorageAdapter {
 31→  private db: Database.Database;
 32→  private initialized = false;
 33→
 34→  constructor(options: SQLiteAdapterOptions) {
 35→    this.db = new Database(options.dbPath);
 36→    this.db.pragma("journal_mode = WAL");
 37→    this.db.pragma("foreign_keys = ON");
 38→  }
 39→
 40→  async initialize(): Promise<void> {
 41→    if (this.initialized) {
 42→      return;
 43→    }
 44→
 45→    this.db.exec(`
 46→      CREATE TABLE IF NOT EXISTS records (
 47→        id TEXT PRIMARY KEY,
 48→        tenant_id TEXT NOT NULL,
 49→        collection TEXT NOT NULL,
 50→        data TEXT NOT NULL,
 51→        created_at TEXT NOT NULL,
 52→        updated_at TEXT NOT NULL
 53→      );
 54→
 55→      CREATE INDEX IF NOT EXISTS idx_records_tenant_collection
 56→        ON records (tenant_id, collection);
 57→    `);
 58→
 59→    this.initialized = true;
 60→  }
 61→
 62→  async create<T extends Record<string, unknown>>(
 63→    tenantId: string,
 64→    collection: string,
 65→    data: T,
 66→  ): Promise<T & { id: string }> {
 67→    const id = crypto.randomUUID();
 68→    const now = new Date().toISOString();
 69→    const record = { ...data, id };
 70→
 71→    this.db
 72→      .prepare(
 73→        "INSERT INTO records (id, tenant_id, collection, data, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ?)",
 74→      )
 75→      .run(id, tenantId, collection, JSON.stringify(record), now, now);
 76→
 77→    return record;
 78→  }
 79→
 80→  async findById<T>(tenantId: string, collection: string, id: string): Promise<T | null> {
 81→    const row = this.db
 82→      .prepare("SELECT data FROM records WHERE id = ? AND tenant_id = ? AND collection = ?")
 83→      .get(id, tenantId, collection) as { data: string } | undefined;
 84→
 85→    if (!row) {
 86→      return null;
 87→    }
 88→
 89→    return JSON.parse(row.data) as T;
 90→  }
 91→
 92→  async findMany<T>(tenantId: string, collection: string, query: QueryFilter): Promise<T[]> {
 93→    const conditions: string[] = ["tenant_id = ?", "collection = ?"];
 94→    const params: unknown[] = [tenantId, collection];
 95→
 96→    if (query.where) {
 97→      for (const [key, value] of Object.entries(query.where)) {
 98→        conditions.push(`json_extract(data, '$.' || ?) = ?`);
 99→        params.push(key, value);
100→      }
101→    }
102→
103→    let sql = `SELECT data FROM records WHERE ${conditions.join(" AND ")}`;
104→
105→    if (query.orderBy && query.orderBy.length > 0) {
106→      const orderClauses = query.orderBy.map((o) => {
107→        if (!/^[a-zA-Z_][a-zA-Z0-9_]*$/.test(o.field)) {
108→          throw new Error(`Invalid order field: ${o.field}`);
109→        }
110→        const dir = o.direction === "desc" ? "DESC" : "ASC";
111→        return `json_extract(data, '$.' || '${o.field}') ${dir}`;
112→      });
113→      sql += ` ORDER BY ${orderClauses.join(", ")}`;
114→    }
115→
116→    if (query.limit !== undefined) {
117→      sql += " LIMIT ?";
118→      params.push(query.limit);
119→    }
120→
121→    if (query.offset !== undefined) {
122→      if (query.limit === undefined) {
123→        sql += " LIMIT -1";
124→      }
125→      sql += " OFFSET ?";
126→      params.push(query.offset);
127→    }
128→
129→    const rows = this.db.prepare(sql).all(...params) as { data: string }[];
130→    return rows.map((row) => JSON.parse(row.data) as T);
131→  }
132→
133→  async update<T extends Record<string, unknown>>(
134→    tenantId: string,
135→    collection: string,
136→    id: string,
137→    data: Partial<T>,
138→  ): Promise<T> {
139→    const existing = await this.findById<T>(tenantId, collection, id);
140→    if (!existing) {
141→      throw new Error(`Record not found: ${id} in collection ${collection} for tenant ${tenantId}`);
142→    }
143→
144→    const updated = { ...existing, ...data, id };
145→    const now = new Date().toISOString();
146→
147→    this.db
148→      .prepare(
149→        "UPDATE records SET data = ?, updated_at = ? WHERE id = ? AND tenant_id = ? AND collection = ?",
150→      )
151→      .run(JSON.stringify(updated), now, id, tenantId, collection);
152→
153→    return updated as T;
154→  }
155→
156→  async delete(tenantId: string, collection: string, id: string): Promise<void> {
157→    this.db
158→      .prepare("DELETE FROM records WHERE id = ? AND tenant_id = ? AND collection = ?")
159→      .run(id, tenantId, collection);
160→  }
161→
162→  async transaction<R>(_tenantId: string, fn: (tx: TransactionContext) => Promise<R>): Promise<R> {
163→    const txContext: TransactionContext = {
164→      create: <T extends Record<string, unknown>>(
165→        txTenantId: string,
166→        collection: string,
167→        data: T,
168→      ) => this.create(txTenantId, collection, data),
169→
170→      findById: <T>(txTenantId: string, collection: string, id: string) =>
171→        this.findById<T>(txTenantId, collection, id),
172→
173→      update: <T extends Record<string, unknown>>(
174→        txTenantId: string,
175→        collection: string,
176→        id: string,
177→        data: Partial<T>,
178→      ) => this.update<T>(txTenantId, collection, id, data),
179→
180→      delete: (txTenantId: string, collection: string, id: string) =>
181→        this.delete(txTenantId, collection, id),
182→    };
183→
184→    // better-sqlite3 is synchronous, so we manually manage BEGIN/COMMIT/ROLLBACK
185→    // to support async transaction callbacks.
186→    this.db.exec("BEGIN");
187→    try {
188→      const result = await fn(txContext);
189→      this.db.exec("COMMIT");
190→      return result;
191→    } catch (error) {
192→      this.db.exec("ROLLBACK");
193→      throw error;
194→    }
195→  }
196→
197→  getMetadata(): StorageMetadata {
198→    return {
199→      adapterName: "sqlite",
200→      adapterVersion: "1.0.0",
201→    };
202→  }
203→
204→  async close(): Promise<void> {
205→    this.db.close();
206→  }
207→}
208→

