 14→
 15→/**
 16→ * Training session API routes.
 17→ * POST /api/training/{tenant}/session — start a new training session (T013)
 18→ *                                      or start remediation for a failed session (T022)
 19→ * GET  /api/training/{tenant}/session — get current session state (T014)
 20→ */
 21→
 22→import { getSnapshot } from "@/config/index";
 23→import { resolveModel } from "@/intake/ai-model-resolver";
 24→import { ProfileRepository } from "@/intake/profile-repository";
 25→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 26→import { logRemediationInitiated, logSessionStarted } from "@/training/audit";
 27→import { CurriculumGenerationError, generateCurriculum } from "@/training/curriculum-generator";
 28→import {
 29→  RemediationPlanError,
 30→  generateRemediationCurriculum,
 31→} from "@/training/remediation-planner";
 32→import { SessionRepository, VersionConflictError } from "@/training/session-repository";
 33→import { transitionSession } from "@/training/state-machine";
 34→import type { TrainingModule } from "@/training/types";
 35→import { NextResponse } from "next/server";
 36→
 37→// ---------------------------------------------------------------------------
 38→// Helper — strip server-only fields from module content before sending
 39→// ---------------------------------------------------------------------------
 40→
 41→function stripServerFields(module: TrainingModule): unknown {
 42→  if (!module.content) return module;
 43→  return {
 44→    ...module,
 45→    content: {
 46→      ...module.content,
 47→      scenarios: module.content.scenarios.map(({ rubric: _rubric, ...s }) => ({
 48→        ...s,
 49→        options: s.options?.map(({ correct: _correct, ...o }) => o),
 50→      })),
 51→      quiz: module.content.quiz
 52→        ? {
 53→            questions: module.content.quiz.questions.map(({ rubric: _rubric, ...q }) => ({
 54→              ...q,
 55→              options: q.options?.map(({ correct: _correct, ...o }) => o),
 56→            })),
 57→          }
 58→        : module.content.quiz,
 59→    },
 60→  };
 61→}
 62→
 63→// ---------------------------------------------------------------------------
 64→// POST — T013: Start a new training session; T022: Remediation
 65→// ---------------------------------------------------------------------------
 66→
 67→export async function POST(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
 68→  const { tenant: tenantSlug } = await params;
 69→  const tenantId = request.headers.get("x-tenant-id");
 70→  const employeeId = request.headers.get("x-employee-id");
 71→
 72→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
 73→    return NextResponse.json(
 74→      { error: "unauthorized", message: "Not authenticated" },
 75→      { status: 401 },
 76→    );
 77→  }
 78→
 79→  // Initialise repositories per-request to avoid connection sharing
 80→  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 81→  const profileRepo = new ProfileRepository(storage);
 82→  const sessionRepo = new SessionRepository(storage);
 83→
 84→  await storage.initialize();
 85→
 86→  // 1. Check for existing active session — 409 if one exists
 87→  const existingSession = await sessionRepo.findActiveSession(tenantId, employeeId);
 88→  if (existingSession) {
 89→    return NextResponse.json(
 90→      { error: "conflict", message: "An active training session already exists" },
 91→      { status: 409 },
 92→    );
 93→  }
 94→
 95→  // Resolve tenant config (needed for both fresh and remediation paths)
 96→  const snapshot = getSnapshot();
 97→  const tenant = snapshot?.tenants.get(tenantSlug);
 98→  if (!tenant) {
 99→    return NextResponse.json({ error: "not_found", message: "Tenant not found" }, { status: 404 });
100→  }
101→  const model = resolveModel(tenant);
102→  const maxModules = tenant.settings.training?.maxModules ?? 8;
103→  const maxAttempts = tenant.settings.training?.maxAttempts ?? 3;
104→  const enableRemediation = tenant.settings.training?.enableRemediation ?? true;
105→
106→  // 2. T022: Check for a failed session with attempts remaining — start remediation
107→  const history = await sessionRepo.findSessionHistory(tenantId, employeeId, { limit: 10 });
108→  const failedSession =
109→    history.find((s) => s.status === "failed" && s.attemptNumber < maxAttempts) ?? null;
110→
111→  if (failedSession) {
112→    // 2a. Remediation must be enabled
113→    if (!enableRemediation) {
114→      return NextResponse.json(
115→        { error: "conflict", message: "Remediation is not enabled for this tenant" },
116→        { status: 409 },
117→      );
118→    }
119→
120→    // 2b. Find confirmed role profile — 404 if none
121→    const profile = await profileRepo.findByEmployee(tenantId, employeeId);
122→    if (!profile) {
123→      return NextResponse.json(
124→        { error: "not_found", message: "No confirmed role profile found" },
125→        { status: 404 },
126→      );
127→    }
128→
129→    // 2c. Generate remediation curriculum focused on weak areas
130→    const weakAreas = failedSession.weakAreas ?? [];
131→    let remediationCurriculum: Awaited<ReturnType<typeof generateRemediationCurriculum>>;
132→    try {
133→      remediationCurriculum = await generateRemediationCurriculum(
134→        weakAreas,
135→        profile,
136→        { maxModules },
137→        model,
138→      );
139→    } catch (error) {
140→      if (error instanceof RemediationPlanError) {
141→        if (error.code === "ai_unavailable") {
142→          return NextResponse.json(
143→            { error: "ai_unavailable", message: "AI service temporarily unavailable" },
144→            { status: 503 },
145→          );
146→        }
147→        return NextResponse.json(
148→          { error: "planning_failed", message: error.message },
149→          { status: 422 },
150→        );
151→      }
152→      return NextResponse.json(
153→        { error: "internal_error", message: "An unexpected error occurred" },
154→        { status: 500 },
155→      );
156→    }
157→
158→    // 2d. Increment attemptNumber and transition the failed session through remediation states
159→    const newAttemptNumber = failedSession.attemptNumber + 1;
160→
161→    // Transition: failed → in-remediation
162→    transitionSession(failedSession.status, "remediation-started");
163→    // Transition: in-remediation → in-progress
164→    transitionSession("in-remediation", "remediation-modules-ready");
165→
166→    // 2e. Update the existing session with new curriculum, status, and attemptNumber
167→    let updatedSession: Awaited<ReturnType<typeof sessionRepo.updateSession>>;
168→    try {
169→      updatedSession = await sessionRepo.updateSession(
170→        tenantId,
171→        failedSession.id,
172→        {
173→          status: "in-progress",
174→          attemptNumber: newAttemptNumber,
175→          curriculum: remediationCurriculum,
176→          weakAreas: null,
177→          aggregateScore: null,
178→          completedAt: null,
179→        },
180→        failedSession.version,
181→      );
182→    } catch (err) {
183→      if (err instanceof VersionConflictError) {
184→        return NextResponse.json(
185→          { error: "conflict", message: "Session was modified by another request" },
186→          { status: 409 },
187→        );
188→      }
189→      throw err;
190→    }
191→
192→    // 2f. Create new module records for the remediation curriculum
193→    const now = new Date().toISOString();
194→    const remediationModuleData = remediationCurriculum.modules.map((m, i) => ({
195→      tenantId,
196→      sessionId: failedSession.id,
197→      moduleIndex: i,
198→      title: m.title,
199→      topicArea: m.topicArea,
200→      jobExpectationIndices: m.jobExpectationIndices,
201→      status: "locked" as const,
202→      content: null,
203→      scenarioResponses: [],
204→      quizAnswers: [],
205→      moduleScore: null,
206→      version: 1,
207→      createdAt: now,
208→      updatedAt: now,
209→    }));
210→
211→    const remediationModules = await sessionRepo.createModules(tenantId, remediationModuleData);
212→
213→    // 2g. Log remediation audit event
214→    await logRemediationInitiated(
215→      storage,
216→      tenantId,
217→      employeeId,
218→      failedSession.id,
219→      newAttemptNumber,
220→      weakAreas.length,
221→      weakAreas,
222→    );
223→
224→    // 2h. Return 201 with updated session + new modules
225→    return NextResponse.json(
226→      { session: updatedSession, modules: remediationModules.map(stripServerFields) },
227→      { status: 201 },
228→    );
229→  }
230→
231→  // 3. No active session and no failed session with attempts remaining — fresh session
232→  // Find confirmed role profile — 404 if none
233→  const profile = await profileRepo.findByEmployee(tenantId, employeeId);
234→  if (!profile) {
235→    return NextResponse.json(
236→      { error: "not_found", message: "No confirmed role profile found" },
237→      { status: 404 },
238→    );
239→  }
240→
241→  // 4. Generate curriculum via AI
242→  let curriculum: Awaited<ReturnType<typeof generateCurriculum>>;
243→  try {
244→    curriculum = await generateCurriculum(profile, { maxModules }, model);
245→  } catch (error) {
246→    if (error instanceof CurriculumGenerationError) {
247→      if (error.code === "ai_unavailable") {
248→        return NextResponse.json(
249→          { error: "ai_unavailable", message: "AI service temporarily unavailable" },
250→          { status: 503 },
251→        );
252→      }
253→      return NextResponse.json(
254→        { error: "generation_failed", message: error.message },
255→        { status: 422 },
256→      );
257→    }
258→    return NextResponse.json(
259→      { error: "internal_error", message: "An unexpected error occurred" },
260→      { status: 500 },
261→    );
262→  }
263→
264→  // 5. Create session record
265→  const now = new Date().toISOString();
266→  const session = await sessionRepo.createSession(tenantId, {
267→    tenantId,
268→    employeeId,
269→    roleProfileId: profile.id,
270→    roleProfileVersion: profile.version,
271→    configHash: snapshot?.configHash ?? "unknown",
272→    appVersion: process.env.APP_VERSION ?? "unknown",
273→    status: "in-progress",
274→    attemptNumber: 1,
275→    curriculum,
276→    aggregateScore: null,
277→    weakAreas: null,
278→    version: 1,
279→    createdAt: now,
280→    updatedAt: now,
281→    completedAt: null,
282→  });
283→
284→  // 6. Create module records for each curriculum module
285→  const moduleData = curriculum.modules.map((m, i) => ({
286→    tenantId,
287→    sessionId: session.id,
288→    moduleIndex: i,
289→    title: m.title,
290→    topicArea: m.topicArea,
291→    jobExpectationIndices: m.jobExpectationIndices,
292→    status: "locked" as const,
293→    content: null,
294→    scenarioResponses: [],
295→    quizAnswers: [],
296→    moduleScore: null,
297→    version: 1,
298→    createdAt: now,
299→    updatedAt: now,
300→  }));
301→
302→  const modules = await sessionRepo.createModules(tenantId, moduleData);
303→
304→  // 7. Log audit event
305→  await logSessionStarted(
306→    storage,
307→    tenantId,
308→    employeeId,
309→    session.id,
310→    1,
311→    profile.version,
312→    snapshot?.configHash ?? "unknown",
313→  );
314→
315→  // 8. Return 201 with session + modules
316→  return NextResponse.json({ session, modules: modules.map(stripServerFields) }, { status: 201 });
317→}
318→
319→// ---------------------------------------------------------------------------
320→// GET — T014: Get current session state
321→// ---------------------------------------------------------------------------
322→
323→export async function GET(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
324→  const { tenant: tenantSlug } = await params;
325→  const tenantId = request.headers.get("x-tenant-id");
326→  const employeeId = request.headers.get("x-employee-id");
327→
328→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
329→    return NextResponse.json(
330→      { error: "unauthorized", message: "Not authenticated" },
331→      { status: 401 },
332→    );
333→  }
334→
335→  // Initialise repositories per-request to avoid connection sharing
336→  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
337→  const sessionRepo = new SessionRepository(storage);
338→
339→  await storage.initialize();
340→
341→  // Parse query parameters
342→  const url = new URL(request.url);
343→  const isHistory = url.searchParams.get("history") === "true";
344→
345→  // T030: History mode — return all sessions with their modules
346→  if (isHistory) {
347→    const sessions = await sessionRepo.findSessionHistory(tenantId, employeeId);
348→    const sessionsWithModules = await Promise.all(
349→      sessions.map(async (sess) => {
350→        const modules = await sessionRepo.findModulesBySession(tenantId, sess.id);
351→        const clientModules = modules.map(stripServerFields);
352→        return { session: sess, modules: clientModules };
353→      }),
354→    );
355→    return NextResponse.json(sessionsWithModules);
356→  }
357→
358→  // T014: Default mode — return active or most recent session
359→  let session = await sessionRepo.findActiveSession(tenantId, employeeId);
360→  if (!session) {
361→    const history = await sessionRepo.findSessionHistory(tenantId, employeeId, { limit: 1 });
362→    session = history[0] ?? null;
363→  }
364→
365→  if (!session) {
366→    return NextResponse.json(
367→      { error: "not_found", message: "No training session found" },
368→      { status: 404 },
369→    );
370→  }
371→
372→  // 2. Find modules for this session
373→  const modules = await sessionRepo.findModulesBySession(tenantId, session.id);
374→
375→  // 3. Strip server-only fields (correct answers, rubrics) from module content
376→  const clientModules = modules.map(stripServerFields);
377→
378→  // 4. Read maxAttempts from tenant config so the UI can display accurate attempt counts
379→  const tenantConfig = getSnapshot()?.tenants.get(tenantSlug);
380→  const maxAttempts = tenantConfig?.settings.training?.maxAttempts ?? 3;
381→
382→  return NextResponse.json({ session, modules: clientModules, maxAttempts });
383→}
