 15→/**
 16→ * Quiz submission API route.
 17→ * POST /api/training/{tenant}/module/{moduleIndex}/quiz
 18→ * Accepts all quiz answers, scores them, and finalises the training module.
 19→ */
 20→
 21→import { getSnapshot } from "@/config/index";
 22→import { resolveModel } from "@/intake/ai-model-resolver";
 23→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 24→import { logModuleCompleted, logQuizSubmitted } from "@/training/audit";
 25→import { EvaluationError, evaluateFreeText } from "@/training/evaluator";
 26→import { MAX_MODULE_INDEX, QuizSubmissionSchema } from "@/training/schemas";
 27→import { computeModuleScore, scoreMcAnswer } from "@/training/score-calculator";
 28→import { SessionRepository, VersionConflictError } from "@/training/session-repository";
 29→import { transitionModule, transitionSession } from "@/training/state-machine";
 30→import { NextResponse } from "next/server";
 31→
 32→export async function POST(
 33→  request: Request,
 34→  { params }: { params: Promise<{ tenant: string; moduleIndex: string }> },
 35→) {
 36→  const { tenant, moduleIndex: moduleIndexStr } = await params;
 37→  const tenantId = request.headers.get("x-tenant-id");
 38→  const employeeId = request.headers.get("x-employee-id");
 39→
 40→  // 1. Auth check
 41→  if (!tenantId || !employeeId || tenantId !== tenant) {
 42→    return NextResponse.json(
 43→      { error: "unauthorized", message: "Not authenticated" },
 44→      { status: 401 },
 45→    );
 46→  }
 47→
 48→  // 2. Parse and validate moduleIndex (0-19)
 49→  const moduleIndex = Number.parseInt(moduleIndexStr, 10);
 50→  if (Number.isNaN(moduleIndex) || moduleIndex < 0 || moduleIndex > MAX_MODULE_INDEX) {
 51→    return NextResponse.json(
 52→      { error: "validation_error", message: "moduleIndex must be an integer between 0 and 19" },
 53→      { status: 400 },
 54→    );
 55→  }
 56→
 57→  // 3. Parse request body
 58→  let body: unknown;
 59→  try {
 60→    body = await request.json();
 61→  } catch {
 62→    return NextResponse.json(
 63→      { error: "invalid_request", message: "Invalid JSON body" },
 64→      { status: 400 },
 65→    );
 66→  }
 67→
 68→  const parsed = QuizSubmissionSchema.safeParse(body);
 69→  if (!parsed.success) {
 70→    return NextResponse.json(
 71→      { error: "validation_error", message: "Invalid quiz submission data" },
 72→      { status: 400 },
 73→    );
 74→  }
 75→
 76→  const submission = parsed.data;
 77→
 78→  // Initialise repositories
 79→  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 80→  const sessionRepo = new SessionRepository(storage);
 81→
 82→  await storage.initialize();
 83→
 84→  // 4. Find active session
 85→  const session = await sessionRepo.findActiveSession(tenantId, employeeId);
 86→  if (!session) {
 87→    return NextResponse.json(
 88→      { error: "not_found", message: "No active training session found" },
 89→      { status: 404 },
 90→    );
 91→  }
 92→
 93→  // Find the module
 94→  const mod = await sessionRepo.findModule(tenantId, session.id, moduleIndex);
 95→  if (!mod) {
 96→    return NextResponse.json({ error: "not_found", message: "Module not found" }, { status: 404 });
 97→  }
 98→
 99→  // 5. Guard: module must be in `quiz-active` state
100→  if (mod.status !== "quiz-active") {
101→    return NextResponse.json(
102→      {
103→        error: "conflict",
104→        message: `Module is in '${mod.status}' state; expected 'quiz-active'`,
105→      },
106→      { status: 409 },
107→    );
108→  }
109→
110→  if (!mod.content) {
111→    return NextResponse.json(
112→      { error: "not_found", message: "Module content not available" },
113→      { status: 404 },
114→    );
115→  }
116→
117→  // 6. Validate all quiz questions are answered
118→  const expectedCount = mod.content.quiz.questions.length;
119→  if (submission.answers.length !== expectedCount) {
120→    return NextResponse.json(
121→      {
122→        error: "validation_error",
123→        message: `Expected ${expectedCount} answers but received ${submission.answers.length}`,
124→      },
125→      { status: 400 },
126→    );
127→  }
128→
129→  // Resolve AI model upfront if any free-text answers exist
130→  const hasFreeText = submission.answers.some((a) => a.responseType === "free-text");
131→  let model: ReturnType<typeof resolveModel> | undefined;
132→
133→  if (hasFreeText) {
134→    const snapshot = getSnapshot();
135→    const tenantConfig = snapshot?.tenants.get(tenantId);
136→    if (!tenantConfig) {
137→      return NextResponse.json(
138→        { error: "not_found", message: "Tenant configuration not found" },
139→        { status: 404 },
140→      );
141→    }
142→    model = resolveModel(tenantConfig);
143→  }
144→
145→  // 7. Score each answer
146→  const now = new Date().toISOString();
147→  const quizAnswers: Array<{
148→    questionId: string;
149→    responseType: "multiple-choice" | "free-text";
150→    selectedOption?: string;
151→    freeTextResponse?: string;
152→    score: number;
153→    llmRationale?: string;
154→    submittedAt: string;
155→  }> = [];
156→
157→  try {
158→    for (const answer of submission.answers) {
159→      const question = mod.content.quiz.questions.find((q) => q.id === answer.questionId);
160→      if (!question) {
161→        return NextResponse.json(
162→          { error: "validation_error", message: `Unknown question id '${answer.questionId}'` },
163→          { status: 400 },
164→        );
165→      }
166→
167→      let score: number;
168→      let llmRationale: string | undefined;
169→
170→      if (answer.responseType === "multiple-choice") {
171→        if (answer.selectedOption === undefined) {
172→          return NextResponse.json(
173→            {
174→              error: "validation_error",
175→              message: `selectedOption is required for multiple-choice question '${answer.questionId}'`,
176→            },
177→            { status: 400 },
178→          );
179→        }
180→        const correctOption = question.options?.find((o) => o.correct)?.key;
181→        if (!correctOption) {
182→          return NextResponse.json(
183→            {
184→              error: "internal_error",
185→              message: `Question '${answer.questionId}' has no correct option defined`,
186→            },
187→            { status: 500 },
188→          );
189→        }
190→        score = scoreMcAnswer(answer.selectedOption, correctOption);
191→      } else {
192→        // free-text — model is guaranteed to be set when hasFreeText is true
193→        const evaluation = await evaluateFreeText(
194→          question.text,
195→          question.rubric ?? "",
196→          answer.freeTextResponse ?? "",
197→          // biome-ignore lint/style/noNonNullAssertion: model is set whenever hasFreeText is true
198→          model!,
199→        );
200→        score = evaluation.score;
201→        llmRationale = evaluation.rationale;
202→      }
203→
204→      quizAnswers.push({
205→        questionId: answer.questionId,
206→        responseType: answer.responseType,
207→        ...(answer.selectedOption !== undefined ? { selectedOption: answer.selectedOption } : {}),
208→        ...(answer.freeTextResponse !== undefined
209→          ? { freeTextResponse: answer.freeTextResponse }
210→          : {}),
211→        score,
212→        ...(llmRationale !== undefined ? { llmRationale } : {}),
213→        submittedAt: now,
214→      });
215→    }
216→  } catch (error) {
217→    if (error instanceof EvaluationError) {
218→      return NextResponse.json(
219→        { error: "ai_unavailable", message: "AI evaluation service temporarily unavailable" },
220→        { status: 503 },
221→      );
222→    }
223→    return NextResponse.json(
224→      { error: "internal_error", message: "An unexpected error occurred during scoring" },
225→      { status: 500 },
226→    );
227→  }
228→
229→  // 9. Compute module score
230→  const scenarioScores = mod.scenarioResponses.map((r) => r.score);
231→  const quizScores = quizAnswers.map((a) => a.score);
232→  const moduleScore = computeModuleScore(scenarioScores, quizScores) ?? 0;
233→
234→  // 10. Transition module to `scored`
235→  const nextModuleStatus = transitionModule(mod.status, "quiz-scored");
236→
237→  // 11. Update module with quizAnswers and moduleScore
238→  try {
239→    await sessionRepo.updateModule(
240→      tenantId,
241→      mod.id,
242→      {
243→        status: nextModuleStatus,
244→        quizAnswers,
245→        moduleScore,
246→      },
247→      mod.version,
248→    );
249→  } catch (updateError) {
250→    if (updateError instanceof VersionConflictError) {
251→      return NextResponse.json(
252→        { error: "conflict", message: "Resource was modified by another request" },
253→        { status: 409 },
254→      );
255→    }
256→    throw updateError;
257→  }
258→
259→  // 12. Log audit events
260→  await logModuleCompleted(
261→    storage,
262→    tenantId,
263→    employeeId,
264→    session.id,
265→    moduleIndex,
266→    mod.title,
267→    moduleScore,
268→  );
269→
270→  const mcCount = quizAnswers.filter((a) => a.responseType === "multiple-choice").length;
271→  const freeTextCount = quizAnswers.filter((a) => a.responseType === "free-text").length;
272→  await logQuizSubmitted(
273→    storage,
274→    tenantId,
275→    employeeId,
276→    session.id,
277→    moduleIndex,
278→    quizAnswers.length,
279→    mcCount,
280→    freeTextCount,
281→  );
282→
283→  // 13. Check if this is the last module; if so, transition session to `evaluating`
284→  // Fetch the full module list once for the total count, then compute scoredCount
285→  // optimistically — previously-scored modules plus the one we just transitioned — to
286→  // avoid a second read that could race with the write we just committed.
287→  const allModules = await sessionRepo.findModulesBySession(tenantId, session.id);
288→  const totalModules = allModules.length;
289→  // Modules already in "scored" state before this request, plus 1 for the module just updated.
290→  const previouslyScoredCount = allModules.filter(
291→    (m) => m.id !== mod.id && m.status === "scored",
292→  ).length;
293→  const scoredCount = previouslyScoredCount + 1;
294→
295→  if (scoredCount === totalModules) {
296→    const freshSession = await sessionRepo.findActiveSession(tenantId, employeeId);
297→    if (!freshSession || freshSession.id !== session.id) {
298→      return NextResponse.json(
299→        { error: "conflict", message: "Resource was modified by another request" },
300→        { status: 409 },
301→      );
302→    }
303→    const nextSessionStatus = transitionSession(freshSession.status, "all-modules-scored");
304→    try {
305→      await sessionRepo.updateSession(
306→        tenantId,
307→        freshSession.id,
308→        { status: nextSessionStatus },
309→        freshSession.version,
310→      );
311→    } catch (sessionUpdateError) {
312→      if (sessionUpdateError instanceof VersionConflictError) {
313→        return NextResponse.json(
314→          { error: "conflict", message: "Resource was modified by another request" },
315→          { status: 409 },
316→        );
317→      }
318→      throw sessionUpdateError;
319→    }
320→  }
321→
322→  // 14. Return 200
323→  return NextResponse.json({
324→    moduleIndex,
325→    moduleScore,
326→    answers: quizAnswers.map((a) => ({
327→      questionId: a.questionId,
328→      score: a.score,
329→      ...(a.llmRationale !== undefined ? { rationale: a.llmRationale } : {}),
330→    })),
331→  });
332→}
