 15→/**
 16→ * Abandon training session API route.
 17→ * POST /api/training/{tenant}/abandon — T032
 18→ * Transitions an in-progress or in-remediation session to abandoned.
 19→ */
 20→
 21→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 22→import { logSessionAbandoned } from "@/training/audit";
 23→import { SessionRepository, VersionConflictError } from "@/training/session-repository";
 24→import { StateTransitionError, transitionSession } from "@/training/state-machine";
 25→import { NextResponse } from "next/server";
 26→
 27→export async function POST(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
 28→  const { tenant: tenantSlug } = await params;
 29→  const tenantId = request.headers.get("x-tenant-id");
 30→  const employeeId = request.headers.get("x-employee-id");
 31→
 32→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
 33→    return NextResponse.json(
 34→      { error: "unauthorized", message: "Not authenticated" },
 35→      { status: 401 },
 36→    );
 37→  }
 38→
 39→  // Initialise repositories per-request to avoid connection sharing
 40→  const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 41→  const sessionRepo = new SessionRepository(storage);
 42→
 43→  await storage.initialize();
 44→
 45→  // 1. Find active session — 404 if none
 46→  const session = await sessionRepo.findActiveSession(tenantId, employeeId);
 47→  if (!session) {
 48→    return NextResponse.json(
 49→      { error: "not_found", message: "No active training session found" },
 50→      { status: 404 },
 51→    );
 52→  }
 53→
 54→  // 2. Guard: session must be in-progress or in-remediation
 55→  if (session.status !== "in-progress" && session.status !== "in-remediation") {
 56→    return NextResponse.json(
 57→      {
 58→        error: "conflict",
 59→        message: `Session is in '${session.status}' state, expected 'in-progress' or 'in-remediation'`,
 60→      },
 61→      { status: 409 },
 62→    );
 63→  }
 64→
 65→  // 3. Validate state transition
 66→  let nextStatus: ReturnType<typeof transitionSession>;
 67→  try {
 68→    nextStatus = transitionSession(session.status, "session-abandoned");
 69→  } catch (err) {
 70→    if (err instanceof StateTransitionError) {
 71→      return NextResponse.json({ error: "conflict", message: err.message }, { status: 409 });
 72→    }
 73→    throw err;
 74→  }
 75→
 76→  // 4. Update session to abandoned with completedAt
 77→  const now = new Date().toISOString();
 78→  let updatedSession: Awaited<ReturnType<typeof sessionRepo.updateSession>>;
 79→  try {
 80→    updatedSession = await sessionRepo.updateSession(
 81→      tenantId,
 82→      session.id,
 83→      {
 84→        status: nextStatus,
 85→        completedAt: now,
 86→      },
 87→      session.version,
 88→    );
 89→  } catch (err) {
 90→    if (err instanceof VersionConflictError) {
 91→      return NextResponse.json(
 92→        { error: "conflict", message: "Session was modified by another request" },
 93→        { status: 409 },
 94→      );
 95→    }
 96→    throw err;
 97→  }
 98→
 99→  // 5. Count modules completed (status "scored")
100→  const modules = await sessionRepo.findModulesBySession(tenantId, session.id);
101→  const modulesCompleted = modules.filter((m) => m.status === "scored").length;
102→  const totalModules = modules.length;
103→
104→  // 6. Log audit event
105→  await logSessionAbandoned(
106→    storage,
107→    tenantId,
108→    employeeId,
109→    session.id,
110→    session.attemptNumber,
111→    modulesCompleted,
112→    totalModules,
113→  );
114→
115→  // 7. Return 200 with updated session
116→  return NextResponse.json({ session: updatedSession }, { status: 200 });
117→}
118→

