 15→/**
 16→ * POST /api/training/{tenant}/module/{moduleIndex}/content
 17→ * Generates content for a specific training module.
 18→ * Idempotent: returns existing content if already generated.
 19→ */
 20→
 21→import { getSnapshot } from "@/config/index";
 22→import { resolveModel } from "@/intake/ai-model-resolver";
 23→import { ProfileRepository } from "@/intake/profile-repository";
 24→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 25→import { ModuleGenerationError, generateModuleContent } from "@/training/module-generator";
 26→import { MAX_MODULE_INDEX } from "@/training/schemas";
 27→import { SessionRepository, VersionConflictError } from "@/training/session-repository";
 28→import { StateTransitionError, transitionModule } from "@/training/state-machine";
 29→import type { ModuleContent } from "@/training/types";
 30→import { NextResponse } from "next/server";
 31→
 32→// ---------------------------------------------------------------------------
 33→// Helper — strip server-only fields from module content for client
 34→// ---------------------------------------------------------------------------
 35→
 36→function toClientContent(content: ModuleContent) {
 37→  return {
 38→    ...content,
 39→    scenarios: content.scenarios.map(({ rubric: _rubric, ...s }) => ({
 40→      ...s,
 41→      options: s.options?.map(({ correct: _correct, ...o }) => o),
 42→    })),
 43→    quiz: {
 44→      questions: content.quiz.questions.map(({ rubric: _rubric, ...q }) => ({
 45→        ...q,
 46→        options: q.options?.map(({ correct: _correct, ...o }) => o),
 47→      })),
 48→    },
 49→  };
 50→}
 51→
 52→// ---------------------------------------------------------------------------
 53→// POST handler
 54→// ---------------------------------------------------------------------------
 55→
 56→export async function POST(
 57→  request: Request,
 58→  { params }: { params: Promise<{ tenant: string; moduleIndex: string }> },
 59→) {
 60→  const { tenant: tenantSlug, moduleIndex: moduleIndexStr } = await params;
 61→  const tenantId = request.headers.get("x-tenant-id");
 62→  const employeeId = request.headers.get("x-employee-id");
 63→
 64→  // 1. Auth check
 65→  if (!tenantId || !employeeId || tenantId !== tenantSlug) {
 66→    return NextResponse.json(
 67→      { error: "unauthorized", message: "Not authenticated" },
 68→      { status: 401 },
 69→    );
 70→  }
 71→
 72→  // 2. Parse and validate moduleIndex
 73→  const moduleIndex = Number(moduleIndexStr);
 74→  if (Number.isNaN(moduleIndex) || moduleIndex < 0 || moduleIndex > MAX_MODULE_INDEX) {
 75→    return NextResponse.json(
 76→      { error: "invalid_request", message: "Invalid module index" },
 77→      { status: 400 },
 78→    );
 79→  }
 80→
 81→  // Initialise repositories
 82→  const adapter = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 83→  const sessionRepo = new SessionRepository(adapter);
 84→  const profileRepo = new ProfileRepository(adapter);
 85→
 86→  await adapter.initialize();
 87→
 88→  let activeSessionId: string | undefined;
 89→
 90→  try {
 91→    // 3. Find active session
 92→    const session = await sessionRepo.findActiveSession(tenantId, employeeId);
 93→    if (session) activeSessionId = session.id;
 94→    if (!session) {
 95→      return NextResponse.json(
 96→        { error: "not_found", message: "No active training session found" },
 97→        { status: 404 },
 98→      );
 99→    }
100→
101→    // 4. Find the module
102→    const module = await sessionRepo.findModule(tenantId, session.id, moduleIndex);
103→    if (!module) {
104→      return NextResponse.json(
105→        { error: "not_found", message: "Module not found" },
106→        { status: 404 },
107→      );
108→    }
109→
110→    // 5. Idempotent: return existing content if already generated
111→    if (module.content !== null) {
112→      return NextResponse.json(toClientContent(module.content), { status: 200 });
113→    }
114→
115→    // 6. Guard: module must be in `locked` status
116→    if (module.status !== "locked") {
117→      return NextResponse.json(
118→        {
119→          error: "conflict",
120→          message: `Module is in '${module.status}' state, expected 'locked'`,
121→        },
122→        { status: 409 },
123→      );
124→    }
125→
126→    // Guard: previous module must be `scored` (for index > 0)
127→    if (moduleIndex > 0) {
128→      const previousModule = await sessionRepo.findModule(tenantId, session.id, moduleIndex - 1);
129→      if (!previousModule || previousModule.status !== "scored") {
130→        return NextResponse.json(
131→          {
132→            error: "conflict",
133→            message: "Previous module must be scored before generating content",
134→          },
135→          { status: 409 },
136→        );
137→      }
138→    }
139→
140→    // 7. Transition module to `content-generating`
141→    const generatingStatus = transitionModule(module.status, "generate-content");
142→    await sessionRepo.updateModule(
143→      tenantId,
144→      module.id,
145→      { status: generatingStatus },
146→      module.version,
147→    );
148→
149→    // 8. Find confirmed role profile
150→    const roleProfile = await profileRepo.findByEmployee(tenantId, employeeId);
151→    if (!roleProfile) {
152→      return NextResponse.json(
153→        { error: "not_found", message: "Role profile not found" },
154→        { status: 404 },
155→      );
156→    }
157→
158→    // 9. Resolve AI model from tenant config
159→    const snapshot = getSnapshot();
160→    const tenant = snapshot?.tenants.get(tenantSlug);
161→    if (!tenant) {
162→      return NextResponse.json(
163→        { error: "not_found", message: "Tenant not found" },
164→        { status: 404 },
165→      );
166→    }
167→    const model = resolveModel(tenant);
168→
169→    // 10. Generate module content
170→    const moduleOutline = {
171→      title: module.title,
172→      topicArea: module.topicArea,
173→      jobExpectationIndices: module.jobExpectationIndices,
174→    };
175→    const content = await generateModuleContent(moduleOutline, roleProfile, model);
176→
177→    // 11. Update module: set content, transition to `learning`
178→    const learningStatus = transitionModule(generatingStatus, "content-ready");
179→    // Re-fetch module to get updated version after first update
180→    const updatedModule = await sessionRepo.findModule(tenantId, session.id, moduleIndex);
181→    if (!updatedModule) {
182→      return NextResponse.json(
183→        { error: "not_found", message: "Module not found after update" },
184→        { status: 404 },
185→      );
186→    }
187→    await sessionRepo.updateModule(
188→      tenantId,
189→      module.id,
190→      { content, status: learningStatus },
191→      updatedModule.version,
192→    );
193→
194→    // 12. Return 200 with client-safe content
195→    return NextResponse.json(toClientContent(content), { status: 200 });
196→  } catch (error) {
197→    if (error instanceof ModuleGenerationError) {
198→      // Roll back module status to `locked` so future retries are not blocked.
199→      try {
200→        const stuckModule = activeSessionId
201→          ? await sessionRepo.findModule(tenantId, activeSessionId, moduleIndex)
202→          : null;
203→        if (stuckModule && stuckModule.status === "content-generating") {
204→          await sessionRepo.updateModule(
205→            tenantId,
206→            stuckModule.id,
207→            { status: "locked" },
208→            stuckModule.version,
209→          );
210→        }
211→      } catch {
212→        // Best-effort rollback — ignore secondary errors
213→      }
214→      if (error.code === "ai_unavailable") {
215→        return NextResponse.json(
216→          { error: "ai_unavailable", message: "AI service temporarily unavailable" },
217→          { status: 503 },
218→        );
219→      }
220→      return NextResponse.json(
221→        { error: "generation_failed", message: error.message },
222→        { status: 422 },
223→      );
224→    }
225→    if (error instanceof VersionConflictError) {
226→      return NextResponse.json(
227→        { error: "conflict", message: "Resource was modified by another request" },
228→        { status: 409 },
229→      );
230→    }
231→    if (error instanceof StateTransitionError) {
232→      return NextResponse.json({ error: "conflict", message: error.message }, { status: 409 });
233→    }
234→    return NextResponse.json(
235→      { error: "internal_error", message: "An unexpected error occurred" },
236→      { status: 500 },
237→    );
238→  }
239→}
240→

