 92→  let newStatus: "passed" | "failed" | "exhausted";
 93→  let completedAt: string | null = null;
 94→  let weakAreas: string[] | undefined;
 95→
 96→  if (isPassing(aggregateScore, passThreshold)) {
 97→    // Pass
 98→    passed = true;
 99→    newStatus = "passed";
100→    nextAction = "complete";
101→    completedAt = now;
102→  } else if (session.attemptNumber < maxAttempts) {
103→    // Failed with attempts remaining
104→    passed = false;
105→    newStatus = "failed";
106→    nextAction = "remediation-available";
107→    weakAreas = identifyWeakAreas(
108→      modules.map((m) => ({ topicArea: m.topicArea, moduleScore: m.moduleScore as number })),
109→      passThreshold,
110→    );
111→  } else {
112→    // Failed and exhausted all attempts
113→    passed = false;
114→    newStatus = "exhausted";
115→    nextAction = "exhausted";
116→    completedAt = now;
117→  }
118→
119→  // Transition session state
120→  try {
121→    transitionSession(
122→      session.status,
123→      `evaluation-${newStatus}` as Parameters<typeof transitionSession>[1],
124→    );
125→  } catch (err) {
126→    if (err instanceof StateTransitionError) {
127→      return NextResponse.json({ error: "conflict", message: err.message }, { status: 409 });
128→    }
129→    throw err;
130→  }
131→
132→  // Update session
133→  const updateData: Parameters<typeof sessionRepo.updateSession>[2] = {
134→    status: newStatus,
135→    aggregateScore,
136→    ...(weakAreas !== undefined ? { weakAreas } : {}),
137→    ...(completedAt !== null ? { completedAt } : {}),
138→  };
139→
140→  try {
141→    await sessionRepo.updateSession(tenantId, session.id, updateData, session.version);
142→  } catch (err) {
143→    if (err instanceof VersionConflictError) {
144→      return NextResponse.json(
145→        { error: "conflict", message: "Session was modified by another request" },
146→        { status: 409 },
147→      );
148→    }
149→    throw err;
150→  }
151→
152→  // Audit logging
153→  await logEvaluationCompleted(
154→    storage,
155→    tenantId,
156→    employeeId,
157→    session.id,
158→    session.attemptNumber,
159→    aggregateScore,
160→    passed,
161→  );
162→
163→  if (newStatus === "exhausted") {
164→    await logSessionExhausted(
165→      storage,
166→      tenantId,
167→      employeeId,
168→      session.id,
169→      aggregateScore,
170→      session.attemptNumber,
171→    );
172→  }
173→
174→  return NextResponse.json(
175→    {
176→      sessionId: session.id,
177→      aggregateScore,
178→      passed,
179→      attemptNumber: session.attemptNumber,
180→      ...(weakAreas !== undefined ? { weakAreas } : {}),
181→      nextAction,
182→    },
183→    { status: 200 },
184→  );
185→}
