 15→/**
 16→ * Confirm role profile API route.
 17→ * POST /api/intake/{tenant}/confirm
 18→ * Persists the confirmed (potentially edited) role profile.
 19→ * Returns 201 for new profiles, 200 for updates.
 20→ */
 21→
 22→import { getSnapshot } from "@/config/index";
 23→import { logProfileConfirmed, logProfileUpdated } from "@/intake/audit";
 24→import { ProfileRepository } from "@/intake/profile-repository";
 25→import { ProfileConfirmationSchema } from "@/intake/schemas";
 26→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 27→import { NextResponse } from "next/server";
 28→
 29→const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 30→const profileRepo = new ProfileRepository(storage);
 31→
 32→export async function POST(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
 33→  const { tenant } = await params;
 34→  const tenantId = request.headers.get("x-tenant-id");
 35→  const employeeId = request.headers.get("x-employee-id");
 36→
 37→  if (!tenantId || !employeeId || tenantId !== tenant) {
 38→    return NextResponse.json(
 39→      { error: "unauthorized", message: "Not authenticated" },
 40→      { status: 401 },
 41→    );
 42→  }
 43→
 44→  // Parse and validate request body
 45→  let body: unknown;
 46→  try {
 47→    body = await request.json();
 48→  } catch {
 49→    return NextResponse.json(
 50→      { error: "invalid_request", message: "Invalid JSON body" },
 51→      { status: 400 },
 52→    );
 53→  }
 54→
 55→  const parsed = ProfileConfirmationSchema.safeParse(body);
 56→  if (!parsed.success) {
 57→    return NextResponse.json(
 58→      { error: "validation_error", message: "Invalid profile confirmation data" },
 59→      { status: 400 },
 60→    );
 61→  }
 62→
 63→  if (parsed.data.jobExpectations.length === 0) {
 64→    return NextResponse.json(
 65→      { error: "validation_error", message: "At least one job expectation is required" },
 66→      { status: 400 },
 67→    );
 68→  }
 69→
 70→  await storage.initialize();
 71→
 72→  // Get config hash for evidence stamping
 73→  const snapshot = getSnapshot();
 74→  const configHash = snapshot?.configHash ?? "unknown";
 75→  const appVersion = process.env.APP_VERSION ?? "0.1.0";
 76→
 77→  // Check if this is a new profile or an update, then persist + audit atomically
 78→  const existingProfile = await profileRepo.findByEmployee(tenantId, employeeId);
 79→
 80→  const profile = await storage.transaction(tenantId, async () => {
 81→    const saved = await profileRepo.confirmProfile(
 82→      tenantId,
 83→      employeeId,
 84→      parsed.data,
 85→      configHash,
 86→      appVersion,
 87→    );
 88→
 89→    // Audit logging inside the same transaction for atomicity
 90→    if (existingProfile) {
 91→      await logProfileUpdated(
 92→        storage,
 93→        tenantId,
 94→        employeeId,
 95→        saved.id,
 96→        existingProfile.version,
 97→        saved.version,
 98→      );
 99→    } else {
100→      await logProfileConfirmed(
101→        storage,
102→        tenantId,
103→        employeeId,
104→        saved.id,
105→        saved.version,
106→        saved.jobExpectations.length,
107→      );
108→    }
109→
110→    return saved;
111→  });
112→
113→  return NextResponse.json(profile, { status: existingProfile ? 200 : 201 });
114→}
115→

