15→/**
16→ * Sign-out API route — destroys session and redirects to IdP logout.
17→ * FR-006: Returns generic 404 for invalid tenant slugs (enumeration protection).
18→ * FR-005: Session destruction on sign-out.
19→ */
20→
21→import { OIDCAdapter } from "@/auth/adapters/oidc-adapter";
22→import { createSignOutEvent, logAuthEvent } from "@/auth/audit";
23→import { destroySession, getSession } from "@/auth/session/session-manager";
24→import { validateTenantSlug } from "@/auth/tenant-validation";
25→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
26→import { NextResponse } from "next/server";
27→
28→const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
29→const oidcAdapter = new OIDCAdapter();
30→
31→async function handleSignOut(
32→  request: Request,
33→  { params }: { params: Promise<{ tenant: string }> },
34→) {
35→  // CSRF protection: validate Origin header matches the request host
36→  const origin = request.headers.get("origin");
37→  const requestUrl = new URL(request.url);
38→  if (!origin || new URL(origin).host !== requestUrl.host) {
39→    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
40→  }
41→
42→  const { tenant: tenantSlug } = await params;
43→
44→  // Validate tenant slug — generic 404 prevents enumeration
45→  const lookup = validateTenantSlug(tenantSlug);
46→  if (!lookup.valid) {
47→    return NextResponse.json({ error: "Organization not found." }, { status: 404 });
48→  }
49→
50→  const { tenant } = lookup;
51→
52→  await storage.initialize();
53→
54→  // Read current session for audit logging
55→  const session = await getSession();
56→  const employee = session.employee;
57→
58→  if (employee) {
59→    // Log sign-out audit event before destroying session
60→    await logAuthEvent(
61→      storage,
62→      createSignOutEvent(tenantSlug, employee.employeeId, employee.idpIssuer, request),
63→    );
64→  }
65→
66→  // Destroy session
67→  await destroySession();
68→
69→  // Get IdP logout redirect
70→  const result = await oidcAdapter.signOut(request, tenant);
71→
72→  if (result.redirectUrl) {
73→    return NextResponse.redirect(result.redirectUrl);
74→  }
75→
76→  // No IdP logout URL configured — redirect to confirmation page
77→  return NextResponse.redirect(new URL(`/${tenantSlug}/auth/signout-confirm`, request.url));
78→}
79→
80→export async function POST(request: Request, context: { params: Promise<{ tenant: string }> }) {
81→  return handleSignOut(request, context);
82→}
