 15→/**
 16→ * OIDC callback API route — exchanges authorization code for tokens.
 17→ * FR-002: Code exchange with PKCE verification.
 18→ * FR-006: Returns generic 404 for invalid tenant slugs (enumeration protection).
 19→ * FR-006: Email domain validation against tenant (tenant-mismatch detection).
 20→ * FR-014: JIT employee provisioning on first sign-in.
 21→ * FR-005: Encrypted session creation with tenant binding.
 22→ */
 23→
 24→import crypto from "node:crypto";
 25→import { OIDCAdapter } from "@/auth/adapters/oidc-adapter";
 26→import { createAuthFailureEvent, createSignInEvent, logAuthEvent } from "@/auth/audit";
 27→import { EmployeeRepository } from "@/auth/employee-repository";
 28→import { createSession } from "@/auth/session/session-manager";
 29→import { validateEmailDomainForTenant, validateTenantSlug } from "@/auth/tenant-validation";
 30→import { SQLiteAdapter } from "@/storage/sqlite-adapter";
 31→import { NextResponse } from "next/server";
 32→
 33→const storage = new SQLiteAdapter({ dbPath: process.env.DB_PATH ?? "data/jem.db" });
 34→const oidcAdapter = new OIDCAdapter();
 35→const employeeRepo = new EmployeeRepository(storage);
 36→
 37→export async function GET(request: Request, { params }: { params: Promise<{ tenant: string }> }) {
 38→  const { tenant: tenantSlug } = await params;
 39→
 40→  // Validate tenant slug — generic 404 prevents enumeration
 41→  const lookup = validateTenantSlug(tenantSlug);
 42→  if (!lookup.valid) {
 43→    return NextResponse.json({ error: "Organization not found." }, { status: 404 });
 44→  }
 45→
 46→  const { tenant } = lookup;
 47→
 48→  await storage.initialize();
 49→
 50→  const result = await oidcAdapter.handleCallback(request, tenant);
 51→
 52→  if (!result.ok) {
 53→    await logAuthEvent(storage, createAuthFailureEvent(tenantSlug, result.reason, request));
 54→    return NextResponse.redirect(
 55→      new URL(`/${tenantSlug}/auth/error?code=${result.reason}`, request.url),
 56→    );
 57→  }
 58→
 59→  // Email domain validation against tenant's configured emailDomains.
 60→  // If the tenant has emailDomains configured and the IdP returns claims
 61→  // for a domain not matching the tenant, reject with tenant-mismatch.
 62→  if (typeof result.claims.email !== "string" || !result.claims.email) {
 63→    await logAuthEvent(
 64→      storage,
 65→      createAuthFailureEvent(tenantSlug, "missing-required-claims", request, result.claims.issuer),
 66→    );
 67→    return NextResponse.redirect(
 68→      new URL(`/${tenantSlug}/auth/error?code=auth_failed`, request.url),
 69→    );
 70→  }
 71→  const emailParts = result.claims.email.split("@");
 72→  if (emailParts.length !== 2 || !emailParts[1]) {
 73→    await logAuthEvent(
 74→      storage,
 75→      createAuthFailureEvent(tenantSlug, "missing-required-claims", request, result.claims.issuer),
 76→    );
 77→    return NextResponse.redirect(
 78→      new URL(`/${tenantSlug}/auth/error?code=auth_failed`, request.url),
 79→    );
 80→  }
 81→  const emailDomain = emailParts[1];
 82→  if (!validateEmailDomainForTenant(tenant, emailDomain)) {
 83→    await logAuthEvent(
 84→      storage,
 85→      createAuthFailureEvent(tenantSlug, "tenant-mismatch", request, result.claims.issuer),
 86→    );
 87→    return NextResponse.redirect(
 88→      new URL(`/${tenantSlug}/auth/error?code=auth_failed`, request.url),
 89→    );
 90→  }
 91→
 92→  // JIT provision employee
 93→  const employee = await employeeRepo.upsertFromClaims(tenantSlug, {
 94→    sub: result.claims.sub,
 95→    email: result.claims.email,
 96→    name: result.claims.name,
 97→  });
 98→
 99→  // Get tenant session TTL from config (default 1 hour)
100→  const sessionTtlSeconds = tenant.settings.auth?.sessionTtlSeconds ?? 3600;
101→  const sessionTtlMs = sessionTtlSeconds * 1000;
102→
103→  // Create session
104→  const now = Date.now();
105→  await createSession({
106→    sessionId: crypto.randomUUID(),
107→    tenantId: tenantSlug,
108→    employeeId: employee.id,
109→    email: employee.email,
110→    displayName: employee.displayName,
111→    idpIssuer: result.claims.issuer,
112→    createdAt: now,
113→    expiresAt: now + sessionTtlMs,
114→  });
115→
116→  // Log sign-in audit event
117→  await logAuthEvent(
118→    storage,
119→    createSignInEvent(tenantSlug, employee.id, result.claims.issuer, request),
120→  );
121→
122→  // Clear auth state cookie and redirect to dashboard
123→  const response = NextResponse.redirect(new URL(`/${tenantSlug}/dashboard`, request.url));
124→  response.cookies.delete("jem_auth_state");
125→  return response;
126→}
